const fs = require('fs');
const path = require('path');

// Удаляем зависшие lock-файлы старше 2 часов
const OUT_DIR_LOCK = '/opt/transcribe/data/results';
if (fs.existsSync(OUT_DIR_LOCK)) {
  const twoHoursAgo = Date.now() - 2 * 60 * 60 * 1000;
  fs.readdirSync(OUT_DIR_LOCK).filter(f => f.endsWith('.lock')).forEach(lf => {
    const lp = path.join(OUT_DIR_LOCK, lf);
    try { if (fs.statSync(lp).mtimeMs < twoHoursAgo) { fs.unlinkSync(lp); } } catch(e) {}
  });
}

const IN_DIR  = '/opt/transcribe/data/uploads';
const OUT_DIR = '/opt/transcribe/data/results';
const MEDIA_EXT = /\.(mp4|mp3|wav|m4a|avi|mov|mkv|webm|ogg|flac)$/i;
const JWT = 'eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJpZCI6Im44bi1pbnRlcm5hbCIsImVtYWlsIjoiYWRtaW5AbWVsa2kudG9wIiwicm9sZSI6ImFkbWluIiwibmFtZSI6Im44biIsImlhdCI6MTc3NTY4ODgxMCwiZXhwIjoyMDkxMjY0ODEwfQ.lmspqxgfE_D4yeT0ibV-akHhA9e457izkIW0Iwv5eB0';

if (!fs.existsSync(IN_DIR)) return [];
if (!fs.existsSync(OUT_DIR)) fs.mkdirSync(OUT_DIR, { recursive: true });

const inFiles = fs.readdirSync(IN_DIR).filter(f => MEDIA_EXT.test(f));

for (const file of inFiles) {
  const baseName = file.replace(/\.[^/.]+$/, '');
  const lockPath   = path.join(OUT_DIR, `${baseName}.lock`);
  const resultPath = path.join(OUT_DIR, `${baseName}_result.txt`);

  // 1) Проверяем статус job в БД — пропускаем done и processing
  let jobData = null;
  try {
    const resp = await $http.get(
      `https://transcribe.melki.top/api/admin/job-by-filename?filename=${encodeURIComponent(file)}`,
      { headers: { Authorization: `Bearer ${JWT}` } }
    );
    jobData = resp;
    if (resp.status === 'completed' || resp.status === 'processing') continue;
  } catch(e) {
    // 404 = job не найден в БД — новый файл, обрабатываем
  }

  // 2) Lock и result файлы — fallback
  if (fs.existsSync(resultPath) || fs.existsSync(lockPath)) continue;
  fs.writeFileSync(lockPath, new Date().toISOString());

  const promptText = (jobData && jobData.prompt_text) || '';

  return [{ json: {
    localPath: path.join(IN_DIR, file),
    fileName:  file,
    baseName:  baseName,
    lockPath:  lockPath,
    resultPath: resultPath,
    promptText: promptText
  }}];
}

return [];

const response = $input.first().json;
const fileInfo = $('Has File?').first().json;

// Diarize флаг из Get Job Info
let diarize = 0;
let min_speakers = null;
let max_speakers = null;
let noise_filter = null;
try {
  const jobInfo = $('Get Job Info').first().json;
  diarize = Number(jobInfo.diarize) || 0;
  min_speakers = jobInfo.min_speakers || null;
  max_speakers = jobInfo.max_speakers || null;
  noise_filter = jobInfo.noise_filter || null;
} catch(e) {}

// Endpoint возвращает { ok, status } — status это строка типа 'ACTIVE'
const status = response?.status || response?.server?.status || 'UNKNOWN';

return [{ json: {
  ...fileInfo,
  diarize,
  min_speakers,
  max_speakers,
  noise_filter,
  gpuStatus:      status,
  needsUnshelve:  status === 'SHELVED_OFFLOADED',
  isReady:        status === 'ACTIVE'
}}];

const response = await $http.post('https://transcribe.melki.top/api/gpu/action', {
  body: { action: 'unshelve' },
  json: true
});

return [{ json: { ...$input.first().json, unshelved: true } }];

const item = $input.all()[0];
const segments = item.json.segments || [];
const fileInfo = $('Has File?').first().json;

function formatTime(sec) {
  const h = Math.floor(sec / 3600);
  const m = Math.floor((sec % 3600) / 60).toString().padStart(2, '0');
  const s = Math.floor(sec % 60).toString().padStart(2, '0');
  if (h > 0) return `${h}:${m}:${s}`;
  return `${m}:${s}`;
}

function formatTimeSRT(sec) {
  const h = Math.floor(sec / 3600).toString().padStart(2, '0');
  const m = Math.floor((sec % 3600) / 60).toString().padStart(2, '0');
  const s = Math.floor(sec % 60).toString().padStart(2, '0');
  const ms = Math.round((sec % 1) * 1000).toString().padStart(3, '0');
  return `${h}:${m}:${s},${ms}`;
}

const JUNK_PHRASES = [
  'thank you for watching', 'thanks for watching',
  'спасибо за просмотр', 'подпишитесь на канал',
  'не забудьте поставить лайк', 'subscribe', 'amara.org', 'субтитры сделаны'
];

let cleanText = '';
let srtText = '';
let srtIndex = 1;
let prevText = '';
const cleanSegments = [];

for (const seg of segments) {
  const text = seg.text.trim();
  if (text.length < 3) continue;
  if (text === prevText) continue;
  prevText = text;
  const lower = text.toLowerCase();
  if (JUNK_PHRASES.some(p => lower.includes(p))) continue;
  if (seg.no_speech_prob > 0.8) continue;

  cleanText += `[${formatTime(seg.start)} - ${formatTime(seg.end)}] ${text}\n`;

  srtText += `${srtIndex}\n${formatTimeSRT(seg.start)} --> ${formatTimeSRT(seg.end)}\n${text}\n\n`;
  srtIndex++;

  cleanSegments.push({ start: seg.start, end: seg.end, text });
}

const MAX_CHARS = 30000;
let finalText = cleanText;
if (cleanText.length > MAX_CHARS) {
  finalText = cleanText.substring(0, MAX_CHARS);
  const lastNewline = finalText.lastIndexOf('\n');
  if (lastNewline > 0) finalText = finalText.substring(0, lastNewline);
  finalText += '\n[...транскрипт обрезан...]';
}

return [{
  json: {
    chunk_data:     finalText,
    file_name:      fileInfo.baseName,
    result_path:    fileInfo.resultPath,
    lock_path:      fileInfo.lockPath,
    segments_count: segments.length,
    result_srt:     srtText,
    result_json:    JSON.stringify(cleanSegments),
    promptText:     fileInfo.promptText || ''   // пробрасываем дальше
  }
}];

const item = $input.all()[0];
// Support both paths: Whisper and Diarize
let cleanData;
try {
  cleanData = $('Clean & Format Transcript').first().json;
} catch(e) {
  try { cleanData = $('Format Diarize Result').first().json; }
  catch(e2) { cleanData = {}; }
}
const response  = item.json.response || '(\u043D\u0435\u0442 \u043E\u0442\u0432\u0435\u0442\u0430 \u043E\u0442 \u043C\u043E\u0434\u0435\u043B\u0438)';
const timestamp = new Date().toLocaleString('ru-RU', {timeZone: 'Europe/Moscow'});
const finalText = [
  `\u041E\u0431\u0440\u0430\u0431\u043E\u0442\u0430\u043D\u043E: ${timestamp}`,
  '',
  '\u2550'.repeat(60),
  '',
  response,
  ''
].join('\n');

// result_clean: для diarize берём готовый plain_text, иначе strip timestamps
const diarizePlain = cleanData.diarize_plain_text || '';
let resultClean;
if (diarizePlain) {
  resultClean = diarizePlain;
} else {
  const rawClean = cleanData.chunk_data || '';
  resultClean = rawClean.replace(/^\[\d{1,2}:\d{2}(?::\d{2})? - \d{1,2}:\d{2}(?::\d{2})?\] /gm, '');
}

return [{ json: {
  result_path:  cleanData.result_path,
  lock_path:    cleanData.lock_path,
  file_name:    cleanData.file_name,
  content:      finalText,
  result_srt:   cleanData.result_srt  || '',
  result_json:  cleanData.result_json || '',
  result_clean: resultClean
}}];

