for (const seg of rawSegments) {
  const speaker = seg.speaker || `Голос ${seg.speaker_id || '?'}`;
  const text = (seg.text || '').trim();
  if (!text || text.length < 3) continue;
  chunkText += `[${formatTime(seg.start)} - ${formatTime(seg.end)}] ${speaker}: ${text}\n`;
  srtText += `${srtIndex}\n${formatTimeSRT(seg.start)} --> ${formatTimeSRT(seg.end)}\n${speaker}: ${text}\n\n`;
  srtIndex++;
  cleanSegs.push({ start: seg.start, end: seg.end, speaker, text });
}

// Fallback: если сервер вернул plain_text вместо segments
if (!chunkText && item.plain_text) chunkText = item.plain_text;
if (!chunkText) chunkText = '(диаризация не вернула данных)';

const MAX_CHARS = 30000;
let finalText = chunkText;
if (chunkText.length > MAX_CHARS) {
  finalText = chunkText.substring(0, MAX_CHARS);
  const lastNL = finalText.lastIndexOf('\n');
  if (lastNL > 0) finalText = finalText.substring(0, lastNL);
  finalText += '\n[...транскрипт обрезан...]';
}

return [{
  json: {
    chunk_data:     finalText,
    file_name:      fileInfo.baseName || gpuInfo.baseName,
    result_path:    fileInfo.resultPath || gpuInfo.resultPath,
    lock_path:      fileInfo.lockPath || gpuInfo.lockPath,
    total_chars:    chunkText.length,
    segments_count: rawSegments.length,
    result_srt:     srtText,
    result_json:    JSON.stringify(cleanSegs),
    promptText:     gpuInfo.promptText || '',
    diarize_plain_text: item.plain_text || ''
  }
}];

// Пробрасываем diarize флаг в JSON (после Read File JSON теряется)
const pgStatus = $('Parse GPU Status').first().json;
const diarize = Number(pgStatus.diarize) || 0;
const min_speakers = pgStatus.min_speakers || null;
const max_speakers = pgStatus.max_speakers || null;
const noise_filter = pgStatus.noise_filter || null;
const items = $input.all();
return items.map(item => ({
  json: { ...item.json, diarize_flag: diarize, min_speakers, max_speakers, noise_filter },
  binary: item.binary
}));
